/**
 * SYNTHETIC DATA — Contract Change Intelligence Engine (Wave 3).
 * The change set mirrors the demo negotiation: AusCare's 1 Aug reply expressed
 * as tracked contractual changes, plus hospital-originated proposals. In
 * production every item is generated by diffing draft versions and enriched
 * with impact/valuation analysis.
 */

export type Originator = 'Health fund' | 'Hospital'
export type Favour = 'Favourable to hospital' | 'Favourable to fund' | 'Neutral'
export type ChangeStatus = 'Open' | 'Countered' | 'Agreed in principle' | 'Rejected' | 'Parked'

export interface ChangeItem {
  id: string
  originator: Originator
  clauseRef: string
  title: string
  currentText: string
  proposedText: string
  favour: Favour
  risk: 'High' | 'Medium' | 'Low'
  priority: number // 1-10
  annualValue: number // + to hospital, − against
  status: ChangeStatus
  owner: string
  impacts: { commercial: string; operational: string; implementation: string }
  summary: string
  action: string
  history: { when: string; what: string }[]
}

